self.onmessage=async e=>{const{id:p,...o}=e.data;for(const e of Object.keys(o))self[e]=o[e];try{let e;if(p<0){const p=self.pyodide;importScripts(p);const o=p.replace(/\/[^/]*$/,"/");self.pyodide=await loadPyodide({indexURL:o}),await self.pyodide.loadPackage("micropip"),await self.pyodide.loadPackage("pydoc_data"),e=await self.pyodide.runPythonAsync('\n      import builtins\n      import micropip\n      import pydoc\n      import pydoc_data  # noqa: F401 — ensure topics for builtins resolve\n      from js import packages, optlite\n      await micropip.install(optlite)\n      for p in packages:\n          await micropip.install(p)\n      pydoc.pager = pydoc.plainpager\n      def _help(*args, **kwargs):\n          if not args:\n              print("Type help(object) for help about object.")\n              return\n          print(pydoc.render_doc(args[0]))\n      builtins.help = _help\n      ')}else await self.pyodide.loadPackagesFromImports(self.script),e=await self.pyodide.runPythonAsync('\n      import builtins\n      import pydoc\n      import pydoc_data  # noqa: F401\n      pydoc.pager = pydoc.plainpager\n      def _help(*args, **kwargs):\n          if not args:\n              print("Type help(object) for help about object.")\n              return\n          print(pydoc.render_doc(args[0]))\n      builtins.help = _help\n      import optlite\n      from js import script, rawInputLst\n      optlite.exec_script(script, rawInputLst)\n      ');self.postMessage({results:e,id:p})}catch(e){self.postMessage({error:"Failed to run code: "+e.message,id:p})}};